from prometheus_client import Counter, CollectorRegistry, GaugeMetricFamily, start_http_server
from flask import Flask, request, jsonify

registry = CollectorRegistry()
counter = Counter(
    registry=registry,
    name='request_total',
    help='Total number of HTTP requests.',
    labelnames=['user_id', 'session_id', 'path']
)

app = Flask(__name__)

@app.before_request
def before_request():
    user_id, session_id, path = request.args.get('user_id'), request.cookies.get('session_id'), request.path
    counter.labels(user_id=user_id, session_id=session_id, path=path).inc()

@app.route('/metrics')
def metrics():
    return registry.finish_collect()

if __name__ == '__main__':
    app.run(debug=True)